// src/App.js
import React, { useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation } from 'react-router-dom';

import Navbar from './Components/Navbar';
import Home from './Components/Home';
import About from './Components/About';
import Gallery from './Components/Gallery';
import Footer from './Components/Footer';

// Initiatives
import FishFarming from './Components/initiatives/FishFarming';
import TableBanking from './Components/initiatives/TableBanking';
import Conservation from './Components/initiatives/Conservation';

// Optional: A proper NotFound page (optional to replace the inline one)
import NotFound from './Components/NotFound';

import './App.css';

// ScrollToTop component
const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

function App() {
  return (
    <Router>
      <ScrollToTop />
      <div className="App">
        <Navbar />
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/about" element={<About />} />
          <Route path="/gallery" element={<Gallery />} />

          {/* Initiatives */}
          <Route path="/Initiatives/fish-farming" element={<FishFarming />} />
          <Route path="/Initiatives/table-banking" element={<TableBanking />} />
          <Route path="/Initiatives/conservation" element={<Conservation />} />

          {/* 404 Not Found */}
          <Route path="*" element={<NotFound />} />
        </Routes>
        <Footer />
      </div>
    </Router>
  );
}

export default App;
